mapper.insert:
/* 토론 참여 점수 반영 ForumJoinUserDAO.insertStdScore */ MERGE INTO TB_LMS_DSCS_PTCP T USING ( SELECT
#{stdId} AS USER_ID
#{userId} AS USER_ID
, #{forumCd} AS DSCS_ID FROM DUAL ) S ON ( T.USER_ID = S.USER_ID AND T.DSCS_ID = S.DSCS_ID ) WHEN MATCHED THEN UPDATE SET T.SCR = CASE WHEN CAST(#{score} AS NUMBER) < 0 THEN 0 WHEN CAST(#{score} AS NUMBER) > 100 THEN 100 ELSE CAST(#{score} AS NUMBER) END, T.TEAM_ID = #{teamCd}, T.EVLYN = 'Y', T.MDFR_ID = #{mdfrId}, T.MOD_DTTM = FN_DTTM() WHEN NOT MATCHED THEN INSERT ( DSCS_PTCP_ID, USER_ID, DSCS_ID, TEAM_ID, SCR, EVLYN, RGTR_ID, REG_DTTM, MDFR_ID, MOD_DTTM, DELYN ) VALUES ( #{dscsPtcpId},
#{stdId}
#{userId}
, #{forumCd}, #{teamCd}, CASE WHEN CAST(NULL AS NUMBER) < 0 THEN 0 WHEN CAST(NULL AS NUMBER) > 100 THEN 100 ELSE CAST(NULL AS NUMBER) END, 'Y', #{rgtrId}, FN_DTTM(), #{mdfrId}, FN_DTTM(), 'N' )

mapper.select:
/* 토론 참여 목록 조회 ForumJoinUserDAO.listStdScore */ SELECT ROW_NUMBER() OVER(ORDER BY stdId ASC) AS lineNo , stdId , score , CASE WHEN atclCnt > 0 OR cmntCnt > 0 THEN '참여' ELSE '미참여' END AS joinStatus , atclCnt , cmntCnt , teamCd FROM ( SELECT A.USER_ID AS stdId , NVL(C.SCR, 0) AS score , (SELECT COUNT(*) FROM TB_LMS_DSCS_ATCL B WHERE B.DSCS_ID = #{forumCd} AND B.USER_ID = A.USER_ID AND B.DELYN = 'N' ) as atclCnt , (SELECT COUNT(*) FROM TB_LMS_DSCS_CMNT B WHERE B.DELYN = 'N' AND B.USER_ID = A.USER_ID AND DSCS_ATCL_ID IN ( SELECT CX.DSCS_ATCL_ID FROM TB_LMS_DSCS_ATCL CX WHERE CX.DSCS_ID = #{forumCd} AND CX.DELYN = 'N' )) AS cmntCnt , C.TEAM_ID AS teamCd FROM TB_LMS_ATNDLC A LEFT JOIN TB_LMS_DSCS_PTCP C ON A.USER_ID = C.USER_ID AND C.DSCS_ID = #{forumCd} WHERE A.SBJCT_ID = #{crsCreCd} AND ATNDLC_STSCD = 'ATNDLC' )T WHERE 1 = 1
AND USER_ID IN
#{item}
AND ( atclCnt > 0 or cmntCnt > 0 )
AND ( atclCnt = 0 and cmntCnt = 0 )
AND USER_ID = #{stdId}

/* 토론 참여 정보 조회 ForumJoinUserDAO.selectForumJoinUser */ SELECT USER_ID AS stdNo , DSCS_ID AS forumCd , SCR AS SCR , EVLYN AS evalYn , RGTR_ID AS rgtrId , REG_DTTM AS regDttm , MDFR_ID AS mdfrId , MOD_DTTM AS modDttm , DELYN AS delYn , ( SELECT B.USER_ID FROM TB_LMS_USER AS B WHERE B.USER_ID = (SELECT C.USER_ID FROM TB_LMS_ATNDLC AS C WHERE C.USER_ID = A.USER_ID) ) AS userId , ( SELECT B.USER_ID FROM TB_LMS_USER AS B WHERE B.USER_ID = (SELECT C.USER_ID FROM TB_LMS_ATNDLC AS C WHERE C.USER_ID = A.USER_ID) ) AS userId , ( SELECT B.USERNM FROM TB_LMS_USER B WHERE B.USER_ID = (SELECT C.USER_ID FROM TB_LMS_ATNDLC AS C WHERE C.USER_ID = A.USER_ID) ) AS userNm
, NVL((SELECT D.DEPTNM FROM TB_LMS_DEPT D WHERE D.DEPT_ID = U.DEPT_ID), '-') AS DEPTNM ,(SELECT COUNT(*) FROM TB_LMS_DSCS_ATCL AS B WHERE B.DSCS_ID = A.DSCS_ID AND B.DELYN ='N' AND B.USER_ID = A.DSCS_ID) AS atclCnt ,(SELECT COUNT(*) FROM TB_LMS_DSCS_CMNT AS B WHERE B.DSCS_ID = A.DSCS_ID AND B.DELYN ='N' AND B.USER_ID = A.DSCS_ID) AS cmntCnt ,(SELECT MTL_EVLYN FROM TB_LMS_DSCS WHERE DSCS_ID = A.DSCS_ID AND DELYN = 'N' ) AS mutEvalYn
,0 AS mutAvg FROM TB_LMS_DSCS_PTCP AS A WHERE USER_ID = #{stdNo} AND DSCS_ID = #{forumCd}

mapper.update:
/*
	교수 메모 수정
	ForumJoinUserDAO.editForumProfMemo
*/
UPDATE TB_LMS_DSCS_PTCP SET
	MDFR_ID = #{mdfrId}
	, MOD_DTTM = FN_DTTM()
	, PROF_MEMO = #{profMemo}
WHERE DSCS_ID = #{forumCd}
	AND USER_ID = #{stdId}

mapper.select:
/*
	토론 참여자 테이블에 해당 참여자가 있는지 체크
	ForumJoinUserDAO.getForumJoinUser
*/
SELECT
	COUNT(*)
FROM TB_LMS_DSCS_PTCP
WHERE USER_ID = #{stdId}
	AND DSCS_ID = #{forumCd}

/*
	메모
	ForumJoinUserDAO.getMemo
*/
SELECT
	PROF_MEMO as profMemo
FROM TB_LMS_DSCS_PTCP
WHERE USER_ID = #{stdId}
	AND DSCS_ID = #{forumCd}

/* 넘겨 받은 글자수에 해당하는 토론 참여자 조회 ForumJoinUserDAO.getSelectCtsLen */ SELECT COUNT(*) FROM TB_LMS_DSCS_PTCP A LEFT JOIN TB_LMS_DSCS_ATCL B ON (A.DSCS_ID = B.DSCS_ID AND A.USER_ID = B.USER_ID AND B.DELYN = 'N')
LEFT JOIN TB_LMS_DSCS_CMNT C ON (B.DSCS_ATCL_ID = C.DSCS_ATCL_ID AND A.USER_ID = C.USER_ID AND C.DELYN = 'N')
WHERE A.DSCS_ID = #{forumCd} AND A.USER_ID = #{stdId} AND B.ATCL_CTS_LEN >= #{ctsLen}
AND (B.ATCL_CTS_LEN >= #{ctsLen} OR C.CMNT_CTS_LEN >= #{ctsLen})

mapper.insert:
/*
	참여자가 없을 때 토론 참여자 테이블 삽입
	ForumJoinUserDAO.chkStdNoInsert
*/
INSERT INTO TB_LMS_DSCS_PTCP (
	USER_ID
	, DSCS_ID
	, RGTR_ID
	, REG_DTTM
)
SELECT
	#{stdId}
	, #{forumCd}
	, 'ADMIN'
	, FN_DTTM()
FROM TB_LMS_DSCS_PTCP
WHERE NOT EXISTS (
	SELECT
		USER_ID
	FROM TB_LMS_DSCS_PTCP
	WHERE USER_ID = #{stdId}
		AND DSCS_ID = #{forumCd}
) ROWNUM = 1

/* 모든 참여자를 토론 참여자 테이블에 삽입 ForumJoinUserDAO.insertJoinUser */ MERGE INTO TB_LMS_DSCS_PTCP TARGET USING ( SELECT A.USER_ID , B.DSCS_ID /* 1. 팀 ID 추출: 토론(B)의 TEAM_ID와 팀원 테이블(E)을 직접 매칭 */ , (SELECT MAX(E.TEAM_ID) FROM TB_LMS_TEAM_MBR E WHERE E.TEAM_ID = B.TEAM_ID /* B.TEAM_TYCD 대신 B.TEAM_ID 사용 */ AND E.USER_ID = A.USER_ID) AS teamCd , #{rgtrId} AS RGTR_ID FROM TB_LMS_ATNDLC A JOIN TB_LMS_DSCS B ON A.SBJCT_ID = B.SBJCT_ID WHERE A.SBJCT_ID = #{crsCreCd} AND B.DSCS_ID = #{forumCd} AND A.ATNDLC_STSCD = 'ATNDLC' AND B.DELYN = 'N'
AND A.USER_ID = #{stdId}
) SOURCE ON (TARGET.USER_ID = SOURCE.USER_ID AND TARGET.DSCS_ID = SOURCE.DSCS_ID)
WHEN MATCHED THEN UPDATE SET TARGET.TEAM_ID = SOURCE.teamCd , TARGET.MDFR_ID = SOURCE.RGTR_ID , TARGET.MOD_DTTM = FN_DTTM()
, TARGET.SCR = 100 , TARGET.EVLYN = 'Y'

/* 참여형 일괄평가 (Oracle 11g 버전) ForumJoinUserDAO.participateScore */ MERGE INTO TB_LMS_DSCS_PTCP TARGET USING ( SELECT T.USER_ID , T.DSCS_ID , T.TEAM_ID /* searchKey에 따른 점수 설정 */
, 0 AS NEW_SCR , 100 AS NEW_SCR
, #{rgtrId} AS RGTR_ID FROM ( SELECT A.USER_ID , A.DSCS_ID , A.TEAM_ID , A.EVLYN /* Oracle 11g 서브쿼리 내 참여도 계산 */ , (SELECT COUNT(*) FROM TB_LMS_DSCS_ATCL WHERE DSCS_ID = A.DSCS_ID AND DELYN = 'N' AND RGTR_ID = A.USER_ID) AS atclCnt FROM TB_LMS_DSCS_PTCP A WHERE A.DSCS_ID = #{forumCd}
AND A.EVLYN = 'N'
) T WHERE 1 = 1
AND T.atclCnt = 0
AND T.atclCnt > 0
) SOURCE ON (TARGET.USER_ID = SOURCE.USER_ID AND TARGET.DSCS_ID = SOURCE.DSCS_ID)
/* SOURCE가 TB_LMS_DSCS_PTCP 자신이므로 WHEN NOT MATCHED는 실행되지 않음 → UPDATE만 유지 */ WHEN MATCHED THEN UPDATE SET TARGET.SCR = SOURCE.NEW_SCR , TARGET.EVLYN = 'Y' , TARGET.MDFR_ID = SOURCE.RGTR_ID , TARGET.MOD_DTTM = FN_DTTM()

mapper.update:
/*
	학습자 팀 수정
	ForumJoinUserDAO.updateStdTeam
*/
UPDATE TB_LMS_DSCS_PTCP SET
	TEAM_ID = #{teamCd}
 WHERE DSCS_ID = #{forumCd}
   AND USER_ID = #{stdId}

/*
	평가여부 초기화
	ForumJoinUserDAO.updateJoinUserEvalN
*/
UPDATE TB_LMS_DSCS_PTCP SET
	  EVLYN = 'N'
	, SCR = NULL
	, MDFR_ID = #{mdfrId}
	, MOD_DTTM = FN_DTTM()
 WHERE DSCS_ID = #{forumCd}
   AND USER_ID = #{stdNo}
